var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>불멸체 코어 완전 파괴. 수복 불가.</color>","JPN":"<color=#ffd34c>不滅体コア、完全破壊。修復不可。</color>","ENG":"<color=#ffd34c>Immortal System Core has been destroyed beyond repair.</color>","TWN":"<color=#ffd34c>不滅者核心完全破壞。不可修復。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>모든...... 기능이....... 영구적으로 정지합니다......</color>","JPN":"<color=#ffd34c>全ての……機能が……永久に停止します……</color>","ENG":"<color=#ffd34c>All system functions will stop permanently.</color>","TWN":"<color=#ffd34c>所有……功能……永久停止……</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"쿨럭! 쿨럭!!","JPN":"ゲホッ……！　ゲホッ……！！","ENG":"*Cough, cough!*","TWN":"咳咳！咳咳！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"내가...... 졌나......?","JPN":"私の……負けか……？","ENG":"Is it... over?","TWN":"我……輸了嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래. 당신이 졌어.","JPN":"そう、あんたの負けだよ。","ENG":"Yes, it's over.","TWN":"沒錯。你輸了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신의 그 바보 같은 계획도 모두 끝이야.","JPN":"あんたのそのバカげた計画も、みんなおしまい。","ENG":"So is your stupid plan.","TWN":"你的愚蠢計畫也全都結束了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"후후...... 바보 같은 소릴......","JPN":"フフ……たわけたことを言うな……","ENG":"Hah hah... Don't be absurd...","TWN":"呵呵……妳說什麼傻話……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"프로젝트 테라사이드에 끝 따윈 없다......","JPN":"プロジェクトテラサイドに終わりなんてない……","ENG":"There's no such thing as an end to Project Terraside...","TWN":"特拉賽德計畫是沒有結束的……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"내가 실패했다면...... 그저...... 다음 사람에게 그 책임이 이어질 뿐이지.","JPN":"私が失敗したら……次の者に引き継がれるだけだ。","ENG":"I may have failed, but... someone else will come to inherit our legacy...","TWN":"如果我失敗了……那也只是……將計畫移交給下一個人罷了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 미련은 버려. 이미 리플레이서 조직도 모두 붕괴했어.","JPN":"余計な未練は捨てれば？　すでにリプレイサーの組織全体が崩壊してるんだから。","ENG":"Just let it go. The Replacer Syndicate has completely been destroyed.","TWN":"放下這些沒用的留戀吧。克隆集團組織也已經崩潰了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"프로젝트 입안자인 당신이 사라지면 다음 사람 같은 건 없어.","JPN":"プロジェクト立案者のあんたが消えたら、次の人なんてないよ。","ENG":"There will be no one to follow your footsteps when you, the author of the plan, are out of the picture.","TWN":"只要你這個計畫負責人消失，就不會再有什麼下一個人了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"큰 착각을...... 하고 있군......","JPN":"大きな勘違いを……しているな……","ENG":"You're sorely mistaken.","TWN":"妳真是……大錯特錯呢……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"쿨럭! 쿨럭!","JPN":"ゴホッ！　ゴホッ！","ENG":"*Cough, cough!*","TWN":"咳咳！咳咳！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"프로젝트 테라사이드는...... 내가 입안한 것이 아니야.","JPN":"プロジェクトテラサイドは……私が立案したものではない。","ENG":"Project Terraside... wasn't a plan I came up with on my own.","TWN":"特拉賽德計畫……不是我策畫的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐...... 라고?","JPN":"えっ……？","ENG":"W-what did you say?","TWN":"你說……什麼？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"난 그저...... 사명을 이어받은 자일 뿐......","JPN":"私はただ……使命を受け継いだだけで……","ENG":"I'm just a missionary chosen for the great cause...","TWN":"我只是……使命的繼承者罷了……"},"stage":{"bg":"MAINSTREAM_5508012","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KING_REPLACER_NULL_TRANS","text":{"KOREA":"프로젝트 테라사이드는...... 아주 오래 전부터...... 시작된 계획이다......","JPN":"プロジェクトテラサイドは……遥か昔から……始まった計画だ……","ENG":"Project Terraside was a plan that has been going on since ages ago...","TWN":"特拉賽德計畫……是從很久以前……就開始的計畫……"},"stage":{"bg":"MAINSTREAM_5508012","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};